svg.script:
(function () {
  var svg = document.documentElement;
  var pl = document.getElementById('pl'), pg = document.getElementById('pg');
  var dc = document.getElementById('dc'), tg = document.getElementById('tg');
  var ro = document.getElementById('ro'), ov = document.getElementById('ov');
  var TMIN = 140, TMAX = 620, X0 = 64, XEND = 700;
  function upd(t) {
    t = Math.max(TMIN, Math.min(TMAX, Math.round(t)));
    pl.setAttribute('x2', t);
    pg.setAttribute('x1', t);
    dc.setAttribute('d', 'M' + t + ' 70 C ' + (t + 25) + ' 90, ' + (t + 40) + ' 160, ' + (t + 60) + ' 230');
    tg.setAttribute('transform', 'translate(' + t + ',70)');
    ro.textContent = 'decay triggered at ' + Math.round((t - X0) / (XEND - X0) * 100) + '% of the plotted run';
  }
  function toX(e) {
    var pt = svg.createSVGPoint();
    pt.x = e.clientX; pt.y = e.clientY;
    return pt.matrixTransform(svg.getScreenCTM().inverse()).x;
  }
  var drag = false;
  ov.addEventListener('pointerdown', function (e) { drag = true; ov.setPointerCapture(e.pointerId); upd(toX(e)); });
  ov.addEventListener('pointermove', function (e) { if (drag) upd(toX(e)); });
  addEventListener('pointerup', function () { drag = false; });
  upd(520);
})();
